<?php
// Generated by Cursor prompt — Service: AuditService — date: 2026-03-15

namespace App\Services;

use Illuminate\Support\Facades\DB;
use Illuminate\Support\Facades\Auth;

class AuditService
{
    /**
     * Kritik bir aksiyonu logla.
     */
    public static function log(
        string  $action,
        ?int    $companyId = null,
        ?string $modelType = null,
        ?int    $modelId   = null,
        ?array  $changes   = null,
        ?int    $userId    = null
    ): void {
        try {
            DB::table('audit_logs')->insert([
                'user_id'    => $userId ?? Auth::id(),
                'company_id' => $companyId ?? Auth::user()?->company_id,
                'action'     => $action,
                'model_type' => $modelType,
                'model_id'   => $modelId,
                'changes'    => $changes ? json_encode($changes) : null,
                'ip'         => request()->ip(),
                'user_agent' => mb_substr(request()->userAgent() ?? '', 0, 200),
                'created_at' => now(),
            ]);
        } catch (\Throwable) {
            // Audit log hatası sistemi durdurmamalı
        }
    }

    /**
     * Bir modelin önce/sonra değişikliklerini kaydet.
     */
    public static function logModelChange(
        string $action,
        object $model,
        array  $before = [],
        array  $after  = []
    ): void {
        static::log(
            action:     $action,
            companyId:  $model->company_id ?? null,
            modelType:  get_class($model),
            modelId:    $model->id ?? null,
            changes:    ['before' => $before, 'after' => $after],
        );
    }

    /**
     * Hassas veri değişikliği (maaş, kimlik no vb.) için özel log.
     */
    public static function logSensitiveChange(
        string $action,
        int    $companyId,
        int    $modelId,
        string $modelType,
        string $field
    ): void {
        static::log(
            action:     "sensitive.{$action}",
            companyId:  $companyId,
            modelType:  $modelType,
            modelId:    $modelId,
            changes:    ['field' => $field, 'note' => 'Hassas alan değişikliği — değer loglanmadı'],
        );
    }
}
